class KongAdminClient:
    """Client for interacting with Kong API Gateway Admin API."""

    def __init__(self, admin_url: str = "http://localhost:8001", timeout: int = 30):
        self.admin_url = admin_url.rstrip("/")
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({
            "Content-Type": "application/json",
            "Accept": "application/json",
        })

    def _request(self, method: str, endpoint: str, data: Optional[dict] = None) -> dict:
        """Make a request to Kong Admin API."""
        url = f"{self.admin_url}{endpoint}"
        try:
            response = self.session.request(
                method=method,
                url=url,
                json=data,
                timeout=self.timeout,
            )
            if response.status_code in (200, 201):
                return {"success": True, "data": response.json(), "status_code": response.status_code}
            elif response.status_code == 409:
                return {"success": False, "error": "Resource already exists", "status_code": 409,
                        "data": response.json()}
            else:
                return {"success": False, "error": response.text, "status_code": response.status_code}
        except requests.exceptions.ConnectionError:
            return {"success": False, "error": f"Cannot connect to Kong Admin API at {url}"}
        except requests.exceptions.Timeout:
            return {"success": False, "error": f"Request to {url} timed out"}
        except Exception as e:
            return {"success": False, "error": str(e)}

    def health_check(self) -> bool:
        """Check if Kong Admin API is reachable."""
        result = self._request("GET", "/status")
        if result.get("success"):
            print("[OK] Kong Admin API is reachable")
            db_status = result["data"].get("database", {}).get("reachable")
            print(f"[OK] Database reachable: {db_status}")
            return True
        else:
            print(f"[ERROR] Kong Admin API unreachable: {result.get('error')}")
