def print_summary(kong: KongAdminClient):
    """Print a summary of the current Kong configuration."""
    services = kong.list_services()
    routes = kong.list_routes()
    upstreams = kong.list_upstreams()
    plugins = kong.list_plugins()

    service_count = len(services.get("data", {}).get("data", [])) if services.get("success") else "?"
    route_count = len(routes.get("data", {}).get("data", [])) if routes.get("success") else "?"
    upstream_count = len(upstreams.get("data", {}).get("data", [])) if upstreams.get("success") else "?"
    plugin_count = len(plugins.get("data", {}).get("data", [])) if plugins.get("success") else "?"

    print(f"  Services:  {service_count}")
    print(f"  Routes:    {route_count}")
    print(f"  Upstreams: {upstream_count}")
    print(f"  Plugins:   {plugin_count}")
    print()

    if services.get("success"):
        print("  Configured Services:")
        for svc in services["data"].get("data", []):
            print(f"    - {svc['name']} -> {svc.get('host', 'N/A')}:{svc.get('port', 'N/A')}")

    if upstreams.get("success"):
        print("\n  Configured Upstreams:")
        for ups in upstreams["data"].get("data", []):
            targets = kong.list_targets(ups["name"])
            target_list = []
            if targets.get("success"):
                target_list = [t["target"] for t in targets["data"].get("data", [])]
            print(f"    - {ups['name']} ({ups.get('algorithm', 'N/A')}): {', '.join(target_list) or 'no targets'}")


def teardown_infrastructure(kong: KongAdminClient):
    """Remove all configured resources (for cleanup/testing)."""
    print("=" * 60)
    print("  Tearing down Kong configuration")
    print("=" * 60)
    print()

    # Delete routes first (they depend on services)
    routes = kong.list_routes()
    if routes.get("success"):
        for route in routes["data"].get("data", []):
            route_id = route.get("name") or route.get("id")
            kong.delete_route(route_id)
            print(f"[OK] Deleted route: {route_id}")

    # Delete plugins
    plugins = kong.list_plugins()
    if plugins.get("success"):
        for plugin in plugins["data"].get("data", []):
            plugin_id = plugin.get("id")
            kong._request("DELETE", f"/plugins/{plugin_id}")
            print(f"[OK] Deleted plugin: {plugin.get('name')} ({plugin_id})")

    # Delete services
    services = kong.list_services()
    if services.get("success"):
        for svc in services["data"].get("data", []):
            svc_name = svc.get("name") or svc.get("id")
            kong.delete_service(svc_name)
            print(f"[OK] Deleted service: {svc_name}")

    # Delete upstreams (targets are deleted with upstreams)
    upstreams = kong.list_upstreams()
    if upstreams.get("success"):
        for ups in upstreams["data"].get("data", []):
            ups_name = ups.get("name") or ups.get("id")
            kong.delete_upstream(ups_name)

    print("\n[DONE] All resources cleaned up")


def load_config_from_file(kong: KongAdminClient, config_path: str):
    """Load configuration from a JSON file and apply it."""
    with open(config_path, "r") as f:
        config = json.load(f)

    print(f"[INFO] Loading configuration from {config_path}")

    # Process upstreams
    for upstream in config.get("upstreams", []):
        targets = upstream.pop("targets", [])
        kong.create_upstream(**upstream)
        for target in targets:
            kong.add_target(upstream["name"], **target)

    # Process services
    for service in config.get("services", []):
        kong.create_service(**service)

    # Process routes
    for route in config.get("routes", []):
        kong.create_route(**route)

    # Process plugins
    for plugin in config.get("plugins", []):
        kong.add_plugin(**plugin)

    # Process consumers
    for consumer in config.get("consumers", []):
        credentials = consumer.pop("credentials", {})
        kong.create_consumer(**consumer)
        for key in credentials.get("key_auth", []):
            kong.add_key_auth(consumer["username"], key=key)
        for basic in credentials.get("basic_auth", []):
            kong.add_basic_auth(consumer["username"], **basic)


