if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="Kong API Gateway Infrastructure Automation")
    parser.add_argument(
        "--admin-url",
        default="http://localhost:8001",
        help="Kong Admin API URL (default: http://localhost:8001)",
    )
    parser.add_argument(
        "--action",
        choices=["setup", "teardown", "status", "load-config", "generate-sample"],
        default="setup",
        help="Action to perform (default: setup)",
    )
    parser.add_argument(
        "--config-file",
        help="Path to JSON configuration file (for load-config action)",
    )
    parser.add_argument(
        "--timeout",
        type=int,
        default=30,
        help="Request timeout in seconds (default: 30)",
    )

    args = parser.parse_args()
    kong_client = KongAdminClient(admin_url=args.admin_url, timeout=args.timeout)

    if args.action == "setup":
        setup_infrastructure(kong_client)
    elif args.action == "teardown":
        teardown_infrastructure(kong_client)
    elif args.action == "status":
        print("--- Kong Status ---")
        kong_client.health_check()
        print()
        print_summary(kong_client)
    elif args.action == "load-config":
        if not args.config_file:
            print("[ERROR] --config-file is required for load-config action")
            sys.exit(1)
        load_config_from_file(kong_client, args.config_file)
    elif args.action == "generate-sample":
        generate_sample_config()

    print("\n[DONE] Kong infrastructure automation complete.")